{"version":3,"file":"index.js","sources":[".out/chars.js",".out/util.js",".out/cache.js",".out/to-char-set.js",".out/basic.js",".out/equal.js",".out/follow.js",".out/next-char.js",".out/longest-prefix.js",".out/determinism.js",".out/consumed-chars.js",".out/reorder.js"],"sourcesContent":["/* eslint-disable @typescript-eslint/no-namespace */\nimport { CharSet, JS } from \"refa\";\nfunction isUnicode(flags) {\n    return flags.unicode || !!flags.unicodeSets;\n}\n/**\n * A set of functions to get predefined character sets.\n */\nexport var Chars;\n(function (Chars) {\n    /**\n     * Returns the maximum character for the given flags.\n     */\n    function maxChar(flags) {\n        if (isUnicode(flags)) {\n            return 1114111 /* MaxChar.UNICODE */;\n        }\n        else {\n            return 65535 /* MaxChar.UTF16 */;\n        }\n    }\n    Chars.maxChar = maxChar;\n    const EMPTY_UTF16_CHARSET = CharSet.empty(65535 /* MaxChar.UTF16 */);\n    const EMPTY_UNICODE_CHARSET = CharSet.empty(1114111 /* MaxChar.UNICODE */);\n    /**\n     * Returns the empty character set for the given flags.\n     */\n    function empty(flags) {\n        if (isUnicode(flags)) {\n            return EMPTY_UNICODE_CHARSET;\n        }\n        else {\n            return EMPTY_UTF16_CHARSET;\n        }\n    }\n    Chars.empty = empty;\n    const ALL_UTF16_CHARSET = CharSet.all(65535 /* MaxChar.UTF16 */);\n    const ALL_UNICODE_CHARSET = CharSet.all(1114111 /* MaxChar.UNICODE */);\n    /**\n     * Returns the full character set for the given flags.\n     */\n    function all(flags) {\n        if (isUnicode(flags)) {\n            return ALL_UNICODE_CHARSET;\n        }\n        else {\n            return ALL_UTF16_CHARSET;\n        }\n    }\n    Chars.all = all;\n    const LINE_TERMINATOR_UTF16_CHARSET = JS.createCharSet([{ kind: \"any\" }], { unicode: false }).negate();\n    const LINE_TERMINATOR_UNICODE_CHARSET = JS.createCharSet([{ kind: \"any\" }], { unicode: true }).negate();\n    /**\n     * Returns the character set that contains only line terminators.\n     *\n     * This character set accepts all characters that the JS RegExp `.` rejects. The returned character set accepts\n     * all character that the regex `/^.$/` rejects.\n     */\n    function lineTerminator(flags) {\n        if (isUnicode(flags)) {\n            return LINE_TERMINATOR_UNICODE_CHARSET;\n        }\n        else {\n            return LINE_TERMINATOR_UTF16_CHARSET;\n        }\n    }\n    Chars.lineTerminator = lineTerminator;\n    const WORD_UTF16_CHARSET = JS.createCharSet([{ kind: \"word\", negate: false }], { unicode: false });\n    const WORD_UNICODE_CHARSET = JS.createCharSet([{ kind: \"word\", negate: false }], {\n        unicode: true,\n        ignoreCase: false,\n    });\n    const WORD_UNICODE_IGNORE_CASE_CHARSET = JS.createCharSet([{ kind: \"word\", negate: false }], {\n        unicode: true,\n        ignoreCase: true,\n    });\n    /**\n     * Returns a character set that is equivalent to `\\w` with the given flags.\n     *\n     * Note: `\\w` is somewhat special because it has 3 values. All predefined character sets only have two values - one\n     * for Unicode mode and one for non-Unicode mode. This is because Unicode-mode changes the semantics of ignore case\n     * as well. This causes some of the ASCII letters to be ignore-case-equal to higher Unicode characters\n     * (e.g. K (Latin Capital Letter K, U+004b) == k (Latin Small Letter K, U+006b) == K (Kelvin Sign, U+212A)). As a\n     * result `\\w` has 3 values: one for non-Unicode mode, one for case-sensitive Unicode-mode, and one for\n     * case-insensitive Unicode-mode.\n     */\n    function word(flags) {\n        if (isUnicode(flags)) {\n            if (flags.ignoreCase) {\n                return WORD_UNICODE_IGNORE_CASE_CHARSET;\n            }\n            else {\n                return WORD_UNICODE_CHARSET;\n            }\n        }\n        else {\n            return WORD_UTF16_CHARSET;\n        }\n    }\n    Chars.word = word;\n    const DIGIT_UTF16_CHARSET = JS.createCharSet([{ kind: \"digit\", negate: false }], { unicode: false });\n    const DIGIT_UNICODE_CHARSET = JS.createCharSet([{ kind: \"digit\", negate: false }], { unicode: true });\n    /**\n     * Returns a character set that is equivalent to `\\d` with the given flags.\n     */\n    function digit(flags) {\n        if (isUnicode(flags)) {\n            return DIGIT_UNICODE_CHARSET;\n        }\n        else {\n            return DIGIT_UTF16_CHARSET;\n        }\n    }\n    Chars.digit = digit;\n    const SPACE_UTF16_CHARSET = JS.createCharSet([{ kind: \"space\", negate: false }], { unicode: false });\n    const SPACE_UNICODE_CHARSET = JS.createCharSet([{ kind: \"space\", negate: false }], { unicode: true });\n    /**\n     * Returns a character set that is equivalent to `\\s` with the given flags.\n     */\n    function space(flags) {\n        if (isUnicode(flags)) {\n            return SPACE_UNICODE_CHARSET;\n        }\n        else {\n            return SPACE_UTF16_CHARSET;\n        }\n    }\n    Chars.space = space;\n})(Chars || (Chars = {}));\n","import { CharSet } from \"refa\";\nimport { Chars } from \"./chars\";\nexport function assertNever(value, message) {\n    throw new Error(message || value);\n}\nexport function assertSameParent(alternatives) {\n    let parent = null;\n    for (const a of alternatives) {\n        if (parent === null) {\n            parent = a.parent;\n        }\n        else {\n            if (a.parent !== parent) {\n                throw new Error(\"Expected all alternatives to have the same parent\");\n            }\n        }\n    }\n}\nexport const isReadonlyArray = Array.isArray;\nexport function asReadonlySet(iter) {\n    if (iter instanceof Set) {\n        return iter;\n    }\n    return new Set(iter);\n}\nexport class CharUnion {\n    get char() {\n        return this._exactChars.union(this._inexactChars);\n    }\n    get exact() {\n        // basic idea here is that the union or an exact superset with an inexact subset will be exact\n        return this._exactChars.isSupersetOf(this._inexactChars);\n    }\n    constructor(empty) {\n        this._exactChars = empty;\n        this._inexactChars = empty;\n    }\n    add(char) {\n        if (char.exact) {\n            this._exactChars = this._exactChars.union(char.char);\n        }\n        else {\n            this._inexactChars = this._inexactChars.union(char.char);\n        }\n    }\n    static fromFlags(flags) {\n        return new CharUnion(Chars.empty(flags));\n    }\n    static fromMaximum(maximum) {\n        return new CharUnion(CharSet.empty(maximum));\n    }\n}\nexport function unionInexact(left, right) {\n    const char = left.char.union(right.char);\n    let exact;\n    if (left.exact) {\n        if (right.exact) {\n            exact = true;\n        }\n        else {\n            exact = left.char.isSupersetOf(right.char);\n        }\n    }\n    else {\n        if (right.exact) {\n            exact = right.char.isSupersetOf(left.char);\n        }\n        else {\n            exact = false;\n        }\n    }\n    return { char, exact };\n}\nexport function intersectInexact(left, right) {\n    const char = left.char.intersect(right.char);\n    const exact = (left.exact && right.exact) || char.isEmpty;\n    return { char, exact };\n}\nexport class SetEquivalence {\n    constructor(count) {\n        this.count = count;\n        this._indexes = [];\n        for (let i = 0; i < count; i++) {\n            this._indexes.push(i);\n        }\n    }\n    makeEqual(a, b) {\n        // This works using the following idea:\n        //  1. If the eq set of a and b is the same, then we can stop.\n        //  2. If indexes[a] < indexes[b], then we want to make\n        //     indexes[b] := indexes[a]. However, this means that we lose the\n        //     information about the indexes[b]! So we will store\n        //     oldB := indexes[b], then indexes[b] := indexes[a], and then\n        //     make oldB == a.\n        //  3. If indexes[a] > indexes[b], similar to 2.\n        let aValue = this._indexes[a];\n        let bValue = this._indexes[b];\n        while (aValue !== bValue) {\n            if (aValue < bValue) {\n                this._indexes[b] = aValue;\n                // eslint-disable-next-line no-param-reassign -- x\n                b = bValue;\n                bValue = this._indexes[b];\n            }\n            else {\n                this._indexes[a] = bValue;\n                // eslint-disable-next-line no-param-reassign -- x\n                a = aValue;\n                aValue = this._indexes[a];\n            }\n        }\n    }\n    /**\n     * This returns:\n     *\n     * 1. `eqSet.count`: How many different equivalence classes there are.\n     * 2. `eqSet.indexes`: A map (array) from each element (index) to the index\n     *    of its equivalence class.\n     *\n     * All equivalence class indexes `eqSet.indexes[i]` are guaranteed to\n     * be <= `eqSet.count`.\n     */\n    getEquivalenceSets() {\n        let counter = 0;\n        for (let i = 0; i < this.count; i++) {\n            if (i === this._indexes[i]) {\n                this._indexes[i] = counter++;\n            }\n            else {\n                this._indexes[i] = this._indexes[this._indexes[i]];\n            }\n        }\n        return {\n            count: counter,\n            indexes: this._indexes,\n        };\n    }\n}\n","/**\n * This will create a new cache instance for the given flags.\n *\n * This operation will always create a new cache. If you want to transparently reuse cache instances, use\n * {@link toCache} instead.\n *\n * See {@link Cache} from more information about using caches.\n *\n * @see {@link Cache}\n * @see {@link toCache}\n */\nexport function createCache(flags) {\n    return new CacheInstance(flags);\n}\n/**\n * Returns a cache instance for the given flags.\n *\n * If the given flags are a cache instance, the cache instance will be returned. Otherwise a new cache instance will\n * be created using {@link createCache}.\n *\n * See {@link Cache} from more information about using caches.\n *\n * @see {@link Cache}\n * @see {@link createCache}\n */\nexport function toCache(flags) {\n    return CacheInstance.from(flags);\n}\n/** @internal */\nexport class CacheInstance {\n    constructor(flags) {\n        this.toCharSet = new WeakMap();\n        this.toUnicodeSet = new WeakMap();\n        // eslint-disable-next-line @typescript-eslint/no-explicit-any\n        this.getFirstConsumedCharLTR = new WeakMap();\n        // eslint-disable-next-line @typescript-eslint/no-explicit-any\n        this.getFirstConsumedCharRTL = new WeakMap();\n        this.getLongestPrefix = new Map();\n        this.dotAll = !!flags.dotAll;\n        this.global = !!flags.global;\n        this.hasIndices = !!flags.hasIndices;\n        this.ignoreCase = !!flags.ignoreCase;\n        this.multiline = !!flags.multiline;\n        this.sticky = !!flags.sticky;\n        this.unicode = !!flags.unicode;\n        this.unicodeSets = !!flags.unicodeSets;\n    }\n    static from(flags) {\n        if (flags instanceof CacheInstance) {\n            return flags;\n        }\n        else {\n            return new CacheInstance(flags);\n        }\n    }\n}\n","import { JS } from \"refa\";\nimport { CacheInstance } from \"./cache\";\nimport { Chars } from \"./chars\";\nimport { assertNever, isReadonlyArray } from \"./util\";\n/**\n * Converts the given element or array of elements into a refa `CharSet`.\n *\n * If an array is given, all the character sets of all elements will be unioned. This means that for any two element `a`\n * and `b`, the results of `toCharSet([a, b])` and `toCharSet(a).union(toCharSet(b))` will be the same.\n *\n * This is guaranteed to be equivalent to `toUnicodeSet(char).chars`.\n */\nexport function toCharSet(elements, flags) {\n    if (!JS.isFlags(flags)) {\n        throw new Error(\"Invalid flags.\");\n    }\n    if (!isReadonlyArray(elements)) {\n        return toCharSetSimpleCached(elements, flags);\n    }\n    if (elements.length === 0) {\n        return Chars.empty(flags);\n    }\n    else if (elements.length === 1) {\n        return toCharSetSimpleCached(elements[0], flags);\n    }\n    else {\n        return Chars.empty(flags).union(...elements.map(e => toCharSetSimpleCached(e, flags)));\n    }\n}\nfunction toCharSetSimpleCached(element, flags) {\n    if (flags instanceof CacheInstance) {\n        let cached = flags.toCharSet.get(element);\n        if (cached === undefined) {\n            cached = JS.parseCharSet(element, flags);\n            flags.toCharSet.set(element, cached);\n        }\n        return cached;\n    }\n    else {\n        return JS.parseCharSet(element, flags);\n    }\n}\n/**\n * Converts the given element or array of elements into a refa `UnicodeSet`.\n *\n * If an array is given, all the character sets of all elements will be unioned. This means that for any two element `a`\n * and `b`, the results of `toUnicodeSet([a, b])` and `toUnicodeSet(a).union(toUnicodeSet(b))` will be the same.\n */\nexport function toUnicodeSet(elements, flags) {\n    if (!JS.isFlags(flags)) {\n        throw new Error(\"Invalid flags.\");\n    }\n    if (!isReadonlyArray(elements)) {\n        return toUnicodeSetSimpleCached(elements, flags);\n    }\n    if (elements.length === 0) {\n        return JS.UnicodeSet.empty(Chars.maxChar(flags));\n    }\n    else if (elements.length === 1) {\n        return toUnicodeSetSimpleCached(elements[0], flags);\n    }\n    else {\n        return JS.UnicodeSet.empty(Chars.maxChar(flags)).union(...elements.map(e => toUnicodeSetSimpleCached(e, flags)));\n    }\n}\nfunction toUnicodeSetSimpleCached(element, flags) {\n    if (flags instanceof CacheInstance) {\n        let cached = flags.toUnicodeSet.get(element);\n        if (cached === undefined) {\n            cached = JS.parseUnicodeSet(element, flags);\n            flags.toUnicodeSet.set(element, cached);\n        }\n        return cached;\n    }\n    else {\n        return JS.parseUnicodeSet(element, flags);\n    }\n}\n/**\n * Returns whether the given character class/set matches all characters.\n *\n * This is guaranteed to be equivalent to `toUnicodeSet(char).chars.isAll` but is implemented more efficiently.\n */\nexport function matchesAllCharacters(char, flags) {\n    switch (char.type) {\n        case \"Character\":\n        case \"ClassStringDisjunction\":\n        case \"StringAlternative\":\n            return false;\n        case \"CharacterClassRange\":\n            return char.min.value === 0 && char.max.value === Chars.maxChar(flags);\n        case \"CharacterSet\":\n            if (char.kind === \"property\") {\n                if (char.strings) {\n                    // are currently no properties of strings that match all characters\n                    return false;\n                }\n                return toCharSet(char, flags).isAll;\n            }\n            else if (char.kind === \"any\") {\n                return !!flags.dotAll;\n            }\n            else {\n                return false;\n            }\n        case \"CharacterClass\":\n            if (char.negate) {\n                return char.elements.every(e => matchesNoCharacters(e, flags));\n            }\n            else {\n                if (char.elements.length === 0) {\n                    return false;\n                }\n                else if (char.elements.length === 1) {\n                    return matchesAllCharacters(char.elements[0], flags);\n                }\n                else {\n                    return toUnicodeSet(char, flags).chars.isAll;\n                }\n            }\n        case \"ExpressionCharacterClass\":\n            return matchesAllCharacters(char.expression, flags);\n        case \"ClassIntersection\":\n            return matchesAllCharacters(char.left, flags) && matchesAllCharacters(char.right, flags);\n        case \"ClassSubtraction\":\n            return toUnicodeSet(char, flags).chars.isAll;\n        default:\n            return assertNever(char);\n    }\n}\n/**\n * Returns whether the given character class/set matches no characters.\n *\n * This is guaranteed to be equivalent to `toUnicodeSet(char).isEmpty` but is implemented more efficiently.\n */\nexport function matchesNoCharacters(char, flags) {\n    switch (char.type) {\n        case \"Character\":\n        case \"CharacterClassRange\":\n        case \"ClassStringDisjunction\":\n        case \"StringAlternative\":\n            // all are guaranteed to match at least one character\n            return false;\n        case \"CharacterSet\":\n            if (char.kind === \"property\") {\n                if (char.strings) {\n                    // are currently no properties of strings that match no characters\n                    return false;\n                }\n                return toCharSet(char, flags).isEmpty;\n            }\n            else {\n                return false;\n            }\n        case \"CharacterClass\":\n            if (char.negate) {\n                if (char.elements.length === 0) {\n                    return false;\n                }\n                else if (char.elements.length === 1) {\n                    return matchesAllCharacters(char.elements[0], flags);\n                }\n                else {\n                    return toUnicodeSet(char, flags).isEmpty;\n                }\n            }\n            else {\n                return char.elements.every(e => matchesNoCharacters(e, flags));\n            }\n        case \"ExpressionCharacterClass\":\n            return matchesNoCharacters(char.expression, flags);\n        case \"ClassIntersection\":\n        case \"ClassSubtraction\":\n            return toUnicodeSet(char, flags).isEmpty;\n        default:\n            return assertNever(char);\n    }\n}\n/**\n * Returns whether the given character elements contains strings.\n *\n * This is guaranteed to be equivalent to `!toUnicodeSet(char).accept.isEmpty` but is implemented more efficiently.\n */\nexport function hasStrings(char, flags) {\n    switch (char.type) {\n        case \"Character\":\n        case \"CharacterClassRange\":\n            return false;\n        case \"CharacterSet\":\n            return char.kind === \"property\" && char.strings;\n        case \"CharacterClass\":\n            if (char.negate || !char.unicodeSets) {\n                return false;\n            }\n            else {\n                return char.elements.some(e => hasStrings(e, flags));\n            }\n        case \"ExpressionCharacterClass\":\n            return hasStrings(char.expression, flags);\n        case \"ClassIntersection\":\n        case \"ClassSubtraction\":\n            return !toUnicodeSet(char, flags).accept.isEmpty;\n        case \"ClassStringDisjunction\":\n            return char.alternatives.some(a => hasStrings(a, flags));\n        case \"StringAlternative\":\n            return char.elements.length !== 1;\n        default:\n            return assertNever(char);\n    }\n}\n","import { visitRegExpAST } from \"@eslint-community/regexpp\";\nimport { assertNever, isReadonlyArray } from \"./util\";\nimport { toUnicodeSet } from \"./to-char-set\";\nfunction characterIsEmpty(element, flags) {\n    switch (element.type) {\n        case \"Character\":\n        case \"CharacterSet\":\n        case \"CharacterClassRange\":\n            return false;\n        case \"CharacterClass\":\n            return (element.unicodeSets &&\n                !element.negate &&\n                element.elements.length > 0 &&\n                element.elements.every(e => characterIsEmpty(e, flags)));\n        case \"ExpressionCharacterClass\":\n            return !element.negate && characterIsEmpty(element.expression, flags);\n        case \"ClassIntersection\":\n        case \"ClassSubtraction\": {\n            // we actually need to evaluate the operation to implement this correctly\n            const lengthRange = toUnicodeSet(element, flags).getLengthRange();\n            return lengthRange !== undefined && lengthRange.min === 0 && lengthRange.max === 0;\n        }\n        case \"ClassStringDisjunction\":\n            return element.alternatives.every(e => characterIsEmpty(e, flags));\n        case \"StringAlternative\":\n            return element.elements.length === 0;\n        default:\n            throw assertNever(element);\n    }\n}\nfunction characterIsPotentiallyEmpty(element) {\n    switch (element.type) {\n        case \"Character\":\n        case \"CharacterSet\":\n        case \"CharacterClassRange\":\n            return false;\n        case \"CharacterClass\":\n            return element.unicodeSets && !element.negate && element.elements.some(characterIsPotentiallyEmpty);\n        case \"ExpressionCharacterClass\":\n            return !element.negate && characterIsPotentiallyEmpty(element.expression);\n        case \"ClassIntersection\":\n            return characterIsPotentiallyEmpty(element.left) && characterIsPotentiallyEmpty(element.right);\n        case \"ClassSubtraction\":\n            return characterIsPotentiallyEmpty(element.left) && !characterIsPotentiallyEmpty(element.right);\n        case \"ClassStringDisjunction\":\n            return element.alternatives.some(characterIsPotentiallyEmpty);\n        case \"StringAlternative\":\n            return element.elements.length === 0;\n        default:\n            throw assertNever(element);\n    }\n}\nfunction isInvokeEvery(element, fn) {\n    if (isReadonlyArray(element)) {\n        return element.every(fn);\n    }\n    else {\n        return fn(element);\n    }\n}\nfunction isInvokeSome(element, fn) {\n    if (isReadonlyArray(element)) {\n        return element.some(fn);\n    }\n    else {\n        return fn(element);\n    }\n}\n/**\n * Returns whether all (but at least one of the) paths of the given element do not consume characters.\n *\n * If this function returns `true`, then {@link isPotentiallyZeroLength} is guaranteed to return `true`.\n *\n * ## Backreferences\n *\n * This function uses the same condition for backreferences as {@link isEmpty}.\n *\n * ## Relations\n *\n * - `isZeroLength(e) -> isPotentiallyZeroLength(e)`\n * - `isZeroLength(e) -> getLengthRange(e).max == 0`\n *\n * @see {@link isPotentiallyZeroLength}\n * @see {@link isEmpty}\n * @see {@link isPotentiallyEmpty}\n * @see {@link getLengthRange}\n */\nexport function isZeroLength(element, flags) {\n    return isInvokeEvery(element, e => isZeroLengthImpl(e, flags));\n}\nfunction isZeroLengthImpl(element, flags) {\n    switch (element.type) {\n        case \"Alternative\":\n            return element.elements.every(e => isZeroLengthImpl(e, flags));\n        case \"Assertion\":\n            return true;\n        case \"Character\":\n        case \"CharacterSet\":\n        case \"CharacterClassRange\":\n        case \"CharacterClass\":\n        case \"ExpressionCharacterClass\":\n        case \"ClassIntersection\":\n        case \"ClassSubtraction\":\n        case \"ClassStringDisjunction\":\n        case \"StringAlternative\":\n            return characterIsEmpty(element, flags);\n        case \"Quantifier\":\n            return element.max === 0 || isZeroLengthImpl(element.element, flags);\n        case \"Backreference\":\n            return isEmptyBackreference(element, flags);\n        case \"CapturingGroup\":\n        case \"Group\":\n            return element.alternatives.length > 0 && element.alternatives.every(e => isZeroLengthImpl(e, flags));\n        default:\n            throw assertNever(element);\n    }\n}\n/**\n * Returns whether at least one path of the given element does not consume characters.\n *\n * ## Backreferences\n *\n * This function uses the same condition for backreferences as {@link isPotentiallyEmpty}.\n *\n * ## Relations\n *\n * - `isPotentiallyZeroLength(e) -> getLengthRange(e).min == 0`\n *\n * @see {@link isZeroLength}\n * @see {@link isEmpty}\n * @see {@link isPotentiallyEmpty}\n * @see {@link getLengthRange}\n */\nexport function isPotentiallyZeroLength(element, flags) {\n    if (!isReadonlyArray(element)) {\n        switch (element.type) {\n            case \"Character\":\n            case \"CharacterSet\":\n            case \"CharacterClassRange\":\n            case \"CharacterClass\":\n            case \"ExpressionCharacterClass\":\n            case \"ClassIntersection\":\n            case \"ClassSubtraction\":\n            case \"ClassStringDisjunction\":\n            case \"StringAlternative\":\n                return characterIsPotentiallyEmpty(element);\n        }\n    }\n    return isInvokeSome(element, e => isPotentiallyZeroLengthImpl(e, e, flags));\n}\nfunction isPotentiallyZeroLengthImpl(e, root, flags) {\n    return impl(e);\n    function impl(element) {\n        switch (element.type) {\n            case \"Alternative\":\n                return element.elements.every(impl);\n            case \"Assertion\":\n                return true;\n            case \"Backreference\":\n                return backreferenceIsPotentiallyEmpty(element, root, flags);\n            case \"Character\":\n            case \"CharacterSet\":\n            case \"CharacterClass\":\n            case \"ExpressionCharacterClass\":\n                return characterIsPotentiallyEmpty(element);\n            case \"CapturingGroup\":\n            case \"Group\":\n                return element.alternatives.some(impl);\n            case \"Quantifier\":\n                return element.min === 0 || impl(element.element);\n            default:\n                throw assertNever(element);\n        }\n    }\n}\n/**\n * Returns whether all (but at least one of the) paths of the given element do neither consume characters nor assert\n * characters.\n *\n * If this function returns `true`, then {@link isZeroLength} and {@link isPotentiallyEmpty} are guaranteed to return\n * `true`.\n *\n * ## Backreferences\n *\n * A backreferences will only be considered potentially empty, iff it is empty by the definition of\n * {@link isEmptyBackreference}.\n *\n * ## Relations\n *\n * - `isEmpty(e) -> isZeroLength(e)`\n * - `isEmpty(e) -> isPotentiallyEmpty(e)`\n *\n * @see {@link isZeroLength}\n * @see {@link isPotentiallyZeroLength}\n * @see {@link isPotentiallyEmpty}\n * @see {@link getLengthRange}\n */\nexport function isEmpty(element, flags) {\n    return isInvokeEvery(element, e => isEmptyImpl(e, flags));\n}\nfunction isEmptyImpl(element, flags) {\n    switch (element.type) {\n        case \"Alternative\":\n            return element.elements.every(e => isEmptyImpl(e, flags));\n        case \"Assertion\":\n            return false;\n        case \"Backreference\":\n            return isEmptyBackreference(element, flags);\n        case \"Character\":\n        case \"CharacterSet\":\n        case \"CharacterClassRange\":\n        case \"CharacterClass\":\n        case \"ExpressionCharacterClass\":\n        case \"ClassIntersection\":\n        case \"ClassSubtraction\":\n        case \"ClassStringDisjunction\":\n        case \"StringAlternative\":\n            return characterIsEmpty(element, flags);\n        case \"CapturingGroup\":\n        case \"Group\":\n            return element.alternatives.length > 0 && element.alternatives.every(e => isEmptyImpl(e, flags));\n        case \"Quantifier\":\n            return element.max === 0 || isEmptyImpl(element.element, flags);\n        default:\n            throw assertNever(element);\n    }\n}\n/**\n * Returns whether at least one path of the given element does neither consume characters nor assert characters.\n *\n * ## Backreferences\n *\n * A backreferences will only be considered potentially empty, iff at least one of the following conditions is true:\n *\n * - The backreference is trivially always empty. (see {@link isEmptyBackreference})\n * - The referenced capturing group is a descendant of the given element and at leas